import math

def calcular_nog(G, L, c_gas_entrada, c_gas_salida, c_liquido_entrada, KGa):
    try:
        return (G * (c_gas_entrada - c_gas_salida)) / (L * c_liquido_entrada)
    except ZeroDivisionError:
        return "Error: La concentración de líquido no puede ser cero"

def calcular_htu(G, L, c_gas_entrada, c_gas_salida, c_liquido_entrada, KGa):
    try:
        nog = calcular_nog(G, L, c_gas_entrada, c_gas_salida, c_liquido_entrada, KGa)
        return math.sqrt((nog * KGa) / (math.pi * G))
    except TypeError:
        return "Error: NOG no calculado"

def calcular_zt(htu, caudal_gas):
    try:
        return htu * caudal_gas
    except TypeError:
        return "Error: HTU no calculado"

def calcular_razon_de_absorcion(nog, htu, caudal_gas):
    try:
        return nog * htu / caudal_gas
    except TypeError:
        return "Error: NOG o HTU no calculados"

def calcular_columna_de_absorcion(G, L, c_gas_entrada, c_gas_salida, c_liquido_entrada, KGa):
    try:
        nog = calcular_nog(G, L, c_gas_entrada, c_gas_salida, c_liquido_entrada, KGa)
        htu = calcular_htu(G, L, c_gas_entrada, c_gas_salida, c_liquido_entrada, KGa)
        zt = calcular_zt(htu, G)
        razon_absorcion = calcular_razon_de_absorcion(nog, htu, G)
        return {
            "NOG": nog,
            "HTU": htu,
            "ZT": zt,
            "Razón de absorción": razon_absorcion
        }
    except Exception as e:
        return f"Error: {str(e)}"

if __name__ == "__main__":
    print(calcular_columna_de_absorcion(10, 5, 0.5, 0.2, 0.8, 0.01))
